const item = items[0].json;
const q = String($('Webhook').item.json.body?.query || '').toLowerCase();
const raw = String(item.choices?.[0]?.message?.content || '').trim().toLowerCase();
const firstToken = raw.split(/[^a-z]+/).find(t => t.length > 0) || '';
const llmResearch = firstToken === 'research';
const tooling = /\b(cursor|copilot|github\s*copilot|\bgithub\b|gitlab|windsurf|tabnine|cody|codeium|sourcegraph|continue\s*\.dev|devin|aider|cline|vscode|vs\s*code|jetbrains|intellij|neovim|\bide\b|ai\s*coding|coding\s*assistant|code\s*completion|pair\s*programm|developer\s*tools?|dev\s*tools?|llm\s+for\s+code|replit|bolt\.new|\bv0\b|vercel\s+v0|stackblitz)\b/i.test(q);
const route_label = llmResearch && tooling ? 'research' : 'general';
return { json: { ...item, route_label } };

const input = items?.[0]?.json ?? {};

// If this came from the research pipeline, it's already in the desired schema.
if (typeof input.answer === 'string' && Array.isArray(input.sub_questions) && input.budget_report) {
  return { json: input };
}

// Otherwise, treat it as an OpenAI Chat Completions response from Direct GPT.
const answer = input.choices?.[0]?.message?.content || input.message?.content || 'No answer';
return {
  json: {
    answer,
    sub_questions: [],
    sections: [],
    key_insights: [],
    limitations: ['Answered from general knowledge - not from research corpus'],
    sources_used: [],
    budget_report: { note: 'No research pipeline used - direct GPT response' },
    memory_state: {},
    elapsed_seconds: 0
  }
};
